// Extract event data from router payload
const input = $input.first().json;

// Router sends: { event_id, event_type, project_id, payload }
const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

// Step key is project-specific
const stepKey = `drive_sync:${projectId}`;

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    project_folder_id: payload.project_folder_id,
    step_key: stepKey
  }
};

// Prepare file items for processing
const files = $('Fetch Unsynced Files').all();
const auftragFolder = $input.first().json.drive_folder_id;
const eventData = $('Parse Event Data').first().json;

return files.map(fileItem => ({
  json: {
    file_id: fileItem.json.id,
    file_name: fileItem.json.file_name,
    mime_type: fileItem.json.mime_type,
    storage_path: fileItem.json.storage_path,
    storage_bucket: fileItem.json.storage_bucket,
    auftrag_folder_id: auftragFolder,
    project_id: eventData.project_id,
    event_id: eventData.event_id,
    step_key: eventData.step_key,
    project_folder_id: eventData.project_folder_id,
    // AUTHENTICATED statt PUBLIC!
    storage_url: `https://yetwntwayhmzmhhgdkli.supabase.co/storage/v1/object/authenticated/project-files/${fileItem.json.storage_path}`
  }
}));

// Collect results from all uploaded files
const items = $input.all();
const prepItems = $('Prepare File Items').all();
const eventData = $('Parse Event Data').first().json;

// Build update data and results
const results = items.map((item, idx) => {
  const prep = prepItems[idx].json;
  return {
    file_id: prep.file_id,
    file_name: prep.file_name,
    drive_file_id: item.json.id,
    drive_file_url: `https://drive.google.com/file/d/${item.json.id}/view`
  };
});

// Build SQL for updating all files
const updates = results.map(r => 
  `UPDATE project_files SET drive_file_id = '${r.drive_file_id}', drive_file_url = '${r.drive_file_url}' WHERE id = '${r.file_id}'::uuid`
).join(';\n');

return {
  json: {
    project_id: eventData.project_id,
    event_id: eventData.event_id,
    step_key: eventData.step_key,
    project_folder_id: eventData.project_folder_id,
    files_synced: results.length,
    synced_files: results,
    sql: updates
  }
};

