SELECT complete_workflow_step(
  '{{ $('Collect Upload Results').item.json.step_key }}',
  '{"files_synced": {{ $('Collect Upload Results').item.json.files_synced }}, "project_folder_id": "{{ $('Collect Upload Results').item.json.project_folder_id }}"}'
);

-- Mark input event as processed
DO $$ BEGIN
  UPDATE events SET processed_at = now() WHERE id = '{{ $('Collect Upload Results').item.json.event_id }}'::uuid;
EXCEPTION WHEN invalid_text_representation THEN NULL;
END $$;

-- Emit DRIVE_SETUP_COMPLETE event
INSERT INTO events (event_type, project_id, payload, source_system, source_flow)
VALUES (
  'DRIVE_SETUP_COMPLETE',
  '{{ $('Collect Upload Results').item.json.project_id }}'::uuid,
  '{"files_synced": {{ $('Collect Upload Results').item.json.files_synced }}, "project_folder_id": "{{ $('Collect Upload Results').item.json.project_folder_id }}"}',
  'n8n',
  'M1_04c_Sync_Initial_Files'
)
RETURNING id, event_type::text, project_id;

