  json: {
    status: 'success',
    message: 'DRIVE_SETUP_COMPLETE emitted - no files to sync',
    project_id: $('Prepare No Files').first().json.project_id,
    files_synced: 0
  }
};

// Step already done or in progress
const claimResult = $input.first().json;
const eventData = $('Parse Event Data').first().json;

if (claimResult.current_status === 'DONE') {
  return {
    json: {
      action: 'skip_but_emit',
      reason: 'Files already synced',
      project_folder_id: claimResult.existing_payload?.project_folder_id || eventData.project_folder_id,
      files_synced: claimResult.existing_payload?.files_synced || 0,
      project_id: eventData.project_id,
      event_id: eventData.event_id
    }
  };
}

// IN_PROGRESS
return {
  json: {
    action: 'exit',
    reason: 'Step in progress by another run',
    current_status: claimResult.current_status
  }
};

const data = $input.first().json;
return {
  json: {
    project_id: data.project_id,
    event_id: data.event_id,
    project_folder_id: data.project_folder_id,
    files_synced: data.files_synced
  }
};

